// isTTYWriter reports whether w is a real terminal (an *os.File whose fd is a
// tty). Banners never print to pipes, files, or CI so machine-readable output
// stays clean.
func isTTYWriter(w io.Writer) bool {
	f, ok := w.(*os.File)
	if !ok {
		return false
	}
	return isatty.IsTerminal(f.Fd()) || isatty.IsCygwinTerminal(f.Fd())
}

// colorLevel classifies a terminal's color support: none (not a tty, NO_COLOR,
// or TERM=dumb), truecolor (COLORTERM=truecolor/24bit â€” required for the 24-bit
// half-block logo), or basic 16-color otherwise.
func colorLevel(w io.Writer) colorCap {
	if !isTTYWriter(w) || os.Getenv("NO_COLOR") != "" || os.Getenv("TERM") == "dumb" {
		return colorNone
	}
	if ct := os.Getenv("COLORTERM"); ct == "truecolor" || ct == "24bit" {
		return colorTruecolor
	}
	return colorBasic
}

// PrintLogo writes the full brand banner â€” the mark with a vertically centered
// wordmark beside it â€” to w on an interactive truecolor terminal. On any other
// color-capable terminal it degrades to the compact one-line PrintStartLine; on
// a non-terminal (pipe, file, CI) it writes nothing. Use it for the bare
// `crewship` invocation and the first-run welcome, NOT on every command.
func PrintLogo(w io.Writer, version string) {
	if version == "" {
		version = "dev"
	}
	if colorLevel(w) != colorTruecolor {
		PrintStartLine(w, version)
		return
	}
	start := (len(crewshipLogoArt) - len(logoSideText)) / 2
	if start < 0 {
		start = 0
	}
	fmt.Fprintln(w)
	for i, row := range crewshipLogoArt {
		side := ""
		if j := i - start; j >= 0 && j < len(logoSideText) {
			if t := logoSideText[j]; t != "" {
				side = "   " + fmt.Sprintf(t, version)
			}
		}
		fmt.Fprintln(w, row+side)
	}
	fmt.Fprintln(w)
}

// PrintStartLine writes a single compact brand line â€” a sail glyph, the name in
// brand blue, and the version â€” cheap enough to show on every `crewship start`.
// It adapts to the terminal's color support (truecolor â†’ 24-bit blue, basic â†’
// ANSI blue, NO_COLOR/dumb â†’ plain) and writes nothing when w is not a terminal.
func PrintStartLine(w io.Writer, version string) {
	if !isTTYWriter(w) {
		return
	}
	if version == "" {
		version = "dev"
	}
	var name, ver string
	switch colorLevel(w) {
	case colorTruecolor:
		name = "\x1b[1;38;2;43;144;255mCrewship\x1b[0m"
		ver = "\x1b[38;2;123;140;164m" + version + "\x1b[0m"
	case colorBasic:
		name = "\x1b[1;34mCrewship\x1b[0m"
		ver = "\x1b[2m" + version + "\x1b[0m"
	default:
		name, ver = "Crewship", version
	}
	fmt.Fprintf(w, "\n  â›µ %s %s\n\n", name, ver)
}
